import time
import json
import boto3
from botocore.exceptions import BotoCoreError, ClientError

# Replace 'Your_AWS_Region' with your AWS region and replace 'your_access_key', 
# 'your_secret_key' with your own access keys for the SQS service.
sqs = boto3.client('sqs', region_name='Your_AWS_Region', 
                   aws_access_key_id='your_access_key',
                   aws_secret_access_key='your_secret_key')
# replace 'YOUR_QUEUE_URL' with the URL of your SQS queue.
queue_url = 'YOUR_QUEUE_URL'

def process_message(msg):
    # Assuming that msg is a dict, we parse it and execute actions based on its content.
    if "action" in msg: 
        action = msg["action"]
        if action == "print":
            print(f'Received message: {msg}')
        elif action == "save_to_db":
            # Here you should replace 'YourTableName' and 'YourRegion' with the table name and region of your database.
            dynamodb = boto3.resource('dynamodb', region_name='YourRegion')
            table = dynamodb.Table('YourTableName')
            table.put_item(Item=msg)
        else: 
            print(f"Unsupported action '{action}' in message {msg}")
    else: 
        print(f"No action field in message {msg}")

def poll_queue():
    while True:
        try:
            # Receive messages from SQS queue.
            response = sqs.receive_message(QueueUrl=queue_url, MaxNumberOfMessages=10)
            if 'Messages' in response:
                for msg in response['Messages']:
                    # Parse message body and process it.
                    try: 
                        msg_body = json.loads(msg["Body"])
                        process_message(msg_body)
                    except Exception as e:
                        print(f'Error while processing a message: {e}')    
                    sqs.delete_message(QueueUrl=queue_url, ReceiptHandle=msg['ReceiptHandle'])     
        except BotoCoreError as e:
            print(f"Boto core error occurred: {e}")
        except ClientError as e: 
            if e.response['Error']['Code'] == 'AWS.SimpleQueueService.NonExistentQueue':
                print("The specified queue does not exist.")
            else: 
                raise 
        time.sleep(5) # sleep to avoid sending too many requests at once  
poll_queue()